  testsPassed++;
}

function logFail(message) {
  console.log(`${RED}❌ ${message}${RESET}`);
  testsFailed++;
}

function logInfo(message) {
  console.log(`${YELLOW}ℹ️  ${message}${RESET}`);
}

// Test 1: Weather forecast
async function testWeatherForecast() {
  logTest('Weather Forecast (Hoje)');

  return new Promise((resolve, reject) => {
    const scriptPath = '/job/skills/weather-bot/weather.sh';
    const args = ['today', '-23.55', '-46.70', 'São Paulo Zona Oeste'];

    const child = spawn(scriptPath, args);

    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (data) => {
      stdout += data.toString();
    });

    child.stderr.on('data', (data) => {
      stderr += data.toString();
    });

    child.on('close', (code) => {
      if (code !== 0) {
        logFail(`Weather forecast script failed with code ${code}: ${stderr}`);
        resolve(false);
        return;
      }

      try {
        const result = JSON.parse(stdout.trim());
        if (result.message) {
          logPass('Weather forecast script executed successfully');
          logInfo(`Message preview: ${result.message.substring(0, 100)}...`);
          resolve(true);
        } else {
          logFail('Weather forecast output missing message field');
          resolve(false);
        }
      } catch (error) {
        logFail(`Failed to parse weather forecast JSON: ${error.message}`);
        resolve(false);
      }
    });

    child.on('error', (error) => {
      logFail(`Failed to spawn weather forecast script: ${error.message}`);
      resolve(false);
    });
  });
}

// Test 2: IP Location
async function testIPLocation() {
  logTest('IP-based Location Detection');

  return new Promise((resolve, reject) => {
    http.get('http://ip-api.com/json/', (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.status === 'success' && json.lat && json.lon && json.city) {
            logPass(`IP location detected: ${json.city}, ${json.regionName}`);
            logInfo(`Coordinates: ${json.lat.toFixed(4)}, ${json.lon.toFixed(4)}`);
            resolve(true);
          } else {
            logFail(`IP location API returned error: ${json.message || 'Unknown error'}`);
            resolve(false);
          }
        } catch (error) {
          logFail(`Failed to parse IP location JSON: ${error.message}`);
          resolve(false);
        }
      });
    }).on('error', (error) => {
      logFail(`IP location request failed: ${error.message}`);
      resolve(false);
    });
  });
}

// Test 3: Reverse Geocoding
async function testReverseGeocoding() {
  logTest('Reverse Geocoding (GPS coordinates to location name)');

  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nominatim.openstreetmap.org',
      port: 443,
      path: '/reverse?format=json&lat=-23.55&lon=-46.70&zoom=10&accept-language=pt-BR',
      method: 'GET',
      headers: {
        'User-Agent': 'Perninhasclimabot (Telegram Weather Bot) - Contact admin for API issues',
        'Accept': 'application/json'
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode !== 200) {
          logFail(`Nominatim API returned status ${res.statusCode}`);
          logInfo('This is expected if rate-limited. The code has fallback handling.');
          resolve(true);
          return;
        }

        try {
          const json = JSON.parse(data);
          let locationName = null;

          if (json.display_name) {
            const parts = json.display_name.split(',');
            locationName = parts.slice(0, 2).join(',').trim();
          } else if (json.address) {
            const city = json.address.city || json.address.town || '';
            const state = json.address.state || '';
            locationName = [city, state].filter(Boolean).join(', ');
          }

          if (locationName) {
            logPass(`Reverse geocoding successful: ${locationName}`);
            resolve(true);
          } else {
            logFail('Reverse geocoding returned no location name');
            resolve(false);
          }
        } catch (error) {
          logFail(`Failed to parse reverse geocoding JSON: ${error.message}`);
          resolve(false);
        }
      });
    });

    req.on('error', (error) => {
      logFail(`Reverse geocoding request failed: ${error.message}`);
      logInfo('The code has fallback handling for this error.');
      resolve(true);
    });

    req.end();
  });
}

// Test 4: Geocoding (city name to coordinates)
async function testGeocoding() {
  logTest('Geocoding (City name to coordinates)');

  return new Promise((resolve, reject) => {
    const encodedName = encodeURIComponent('Curitiba');
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodedName}&count=1&language=pt&format=json`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.results && json.results.length > 0) {
            const result = json.results[0];
            logPass(`Geocoding successful: ${result.name}, ${result.country}`);
            logInfo(`Coordinates: ${result.latitude.toFixed(4)}, ${result.longitude.toFixed(4)}`);
            resolve(true);
          } else {
            logFail('Geocoding returned no results');
            resolve(false);
          }
        } catch (error) {
          logFail(`Failed to parse geocoding JSON: ${error.message}`);
          resolve(false);
        }
      });
    }).on('error', (error) => {
      logFail(`Geocoding request failed: ${error.message}`);
      resolve(false);
    });
  });
}

// Test 5: User location storage
function testUserLocationStorage() {
  logTest('User Location Storage (save/load)');

  const userId = 999999;
  const testLocation = {
    lat: -23.55,
    lon: -46.70,
    name: 'São Paulo Zona Oeste'
  };

  try {
    // Create data directory if needed
    if (!fs.existsSync(DATA_DIR)) {
      fs.mkdirSync(DATA_DIR, { recursive: true });
    }

    // Load existing data
    let data = {};
    try {
      const fileContent = fs.readFileSync(USER_LOCATIONS_FILE, 'utf8');
      data = JSON.parse(fileContent);
    } catch (error) {
      // File doesn't exist, start fresh
    }

    // Save location
    data[userId] = testLocation;
    fs.writeFileSync(USER_LOCATIONS_FILE, JSON.stringify(data, null, 2));
    logPass('Location saved successfully');

    // Load location
    const loadData = JSON.parse(fs.readFileSync(USER_LOCATIONS_FILE, 'utf8'));
    const loadedLocation = loadData[userId];

    if (loadedLocation &&
        loadedLocation.lat === testLocation.lat &&
        loadedLocation.lon === testLocation.lon &&
        loadedLocation.name === testLocation.name) {
      logPass('Location loaded successfully and matches saved data');
      return true;
    } else {
      logFail('Loaded location does not match saved data');
      return false;
    }
  } catch (error) {
    logFail(`User location storage failed: ${error.message}`);
    return false;
  }
}

// Test 6: Pending input system
function testPendingInputSystem() {
  logTest('Pending Input System (set/get/clear)');

  const PENDING_INPUT_FILE = path.join(DATA_DIR, 'pending-input.json');
  const userId = 888888;

  try {
    // Create data directory if needed
    if (!fs.existsSync(DATA_DIR)) {
      fs.mkdirSync(DATA_DIR, { recursive: true });
    }

    // Set pending input
    let data = {};
    try {
      const fileContent = fs.readFileSync(PENDING_INPUT_FILE, 'utf8');
      data = JSON.parse(fileContent);
    } catch (error) {
      // File doesn't exist, start fresh
    }

    data[userId] = {
      type: 'city_name',
      timestamp: Date.now()
    };
    fs.writeFileSync(PENDING_INPUT_FILE, JSON.stringify(data, null, 2));
    logPass('Pending input set successfully');

    // Get and clear pending input
    const loadData = JSON.parse(fs.readFileSync(PENDING_INPUT_FILE, 'utf8'));
    const pending = loadData[userId];

    if (pending && pending.type === 'city_name') {
      logPass('Pending input retrieved successfully');

      // Clear pending input
      delete loadData[userId];
      fs.writeFileSync(PENDING_INPUT_FILE, JSON.stringify(loadData, null, 2));
      logPass('Pending input cleared successfully');

      // Verify it's cleared
      const finalData = JSON.parse(fs.readFileSync(PENDING_INPUT_FILE, 'utf8'));
      if (!finalData[userId]) {
        logPass('Pending input verified as cleared');
        return true;
      } else {
        logFail('Pending input not properly cleared');
        return false;
      }
    } else {
      logFail('Pending input retrieval failed');
      return false;
    }
  } catch (error) {
    logFail(`Pending input system failed: ${error.message}`);
    return false;
  }
}

// Run all tests
async function runAllTests() {
  console.log(`${BLUE}╔═══════════════════════════════════════════════════════════════╗${RESET}`);
  console.log(`${BLUE}║  Weather Bot Comprehensive Test Suite                          ║${RESET}`);
  console.log(`${BLUE}╚═══════════════════════════════════════════════════════════════╝${RESET}`);

  // Test 1: Weather Forecast
  const test1 = await testWeatherForecast();

  // Test 2: IP Location
  const test2 = await testIPLocation();

  // Test 3: Reverse Geocoding
  const test3 = await testReverseGeocoding();

  // Test 4: Geocoding
  const test4 = await testGeocoding();

  // Test 5: User Location Storage
  const test5 = testUserLocationStorage();

  // Test 6: Pending Input System
  const test6 = testPendingInputSystem();

  // Summary
  console.log(`\n${BLUE}═══════════════════════════════════════════════════════════════${RESET}`);
  console.log(`${BLUE}  Test Summary${RESET}`);
  console.log(`${BLUE}═══════════════════════════════════════════════════════════════${RESET}`);
  console.log(`${GREEN}✅ Passed: ${testsPassed}${RESET}`);
  console.log(`${RED}❌ Failed: ${testsFailed}${RESET}`);

  if (testsFailed === 0) {
    console.log(`\n${GREEN}🎉 All tests passed!${RESET}`);
    process.exit(0);
  } else {
    console.log(`\n${RED}⚠️  Some tests failed. Please review the errors above.${RESET}`);
    process.exit(1);
  }
}

runAllTests();

