#!/usr/bin/env node
/**
 * Test webhook route flow
 * Simulates what happens when the webhook receives a Telegram update
 */

const { spawn } = require('child_process');
const fs = require('fs');

console.log('=== Webhook Route Flow Test ===\n');

// Test 1: Verify the handler script exists and is executable
console.log('1. Checking if handler script exists...');
if (fs.existsSync('/job/triggers/weather-bot.js')) {
  console.log('✅ Handler script exists: /job/triggers/weather-bot.js');
} else {
  console.log('❌ Handler script not found!');
  process.exit(1);
}

// Test 2: Verify the weather script exists
console.log('\n2. Checking if weather script exists...');
if (fs.existsSync('/job/skills/weather-bot/weather.sh')) {
  console.log('✅ Weather script exists: /job/skills/weather-bot/weather.sh');
} else {
  console.log('❌ Weather script not found!');
  process.exit(1);
}

// Test 3: Test the handler with a mock update
console.log('\n3. Testing handler with mock callback query...');
const mockUpdate = {
  callback_query: {
    id: 'test_callback_id',
    from: { id: 5121600266 },
    message: {
      chat: { id: 5121600266 },
      message_id: 1
    },
    data: 'weather_today'
  }
};

const child = spawn('node', ['/job/triggers/weather-bot.js', JSON.stringify(mockUpdate)], {
  env: {
    ...process.env,
    WEATHER_BOT_TOKEN: 'TEST_TOKEN',
    WEATHER_BOT_ADMIN_ID: '5121600266'
  }
});

let stdout = '';
let stderr = '';

child.stdout.on('data', (data) => {
  stdout += data.toString();
});

child.stderr.on('data', (data) => {
  stderr += data.toString();
});

child.on('close', (code) => {
  console.log('   Handler execution completed');
  console.log('   Exit code:', code);

  if (stdout) {
    console.log('\n   Stdout:');
    console.log('   ' + stdout.split('\n').join('\n   '));
  }

  if (stderr) {
    console.log('\n   Stderr:');
    console.log('   ' + stderr.split('\n').join('\n   '));
  }

  // Check if the handler processed the request
  if (stdout.includes('Callback query received') || stdout.includes('Processing Telegram update')) {
    console.log('\n✅ Handler processed the request correctly');
  } else {
    console.log('\n❌ Handler did not process the request as expected');
  }

  // Check for expected error (Telegram API will fail with test token)
  if (stderr.includes('Bad Request') || stderr.includes('query is too old')) {
    console.log('✅ Handler attempted to call Telegram API (expected error with test token)');
  }

  console.log('\n=== Webhook Flow Test Complete ===');
  console.log('\nNote: The Telegram API call failed because we used a test token.');
  console.log('This is expected. The important thing is that the handler was invoked');
  console.log('and attempted to process the request, which confirms the path fix works.\n');
});

child.on('error', (error) => {
  console.error('❌ Failed to spawn handler:', error);
  process.exit(1);
});

